```java
@Entity @Table(name = "portfolio_positions")
public class PortfolioPosition {
    @Id @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false) private String userId;
    @Column(nullable = false) private String symbol;
    @Column(nullable = false) private int totalQty;
    @Column(nullable = false) private java.math.BigDecimal avgPrice;

    @Version
    private int version;  // ← optimistic lock

    protected PortfolioPosition() {}
    public PortfolioPosition(String userId, String symbol, int qty, java.math.BigDecimal price) {
        this.userId=userId; this.symbol=symbol; this.totalQty=qty; this.avgPrice=price;
    }

    public void applyTrade(int tradedQty, java.math.BigDecimal tradePrice, String type) {
        if ("BUY".equals(type)) {
            // Weighted average price:
            java.math.BigDecimal totalValue = avgPrice.multiply(java.math.BigDecimal.valueOf(totalQty))
                .add(tradePrice.multiply(java.math.BigDecimal.valueOf(tradedQty)));
            totalQty += tradedQty;
            avgPrice = totalValue.divide(java.math.BigDecimal.valueOf(totalQty), 2, java.math.RoundingMode.HALF_UP);
        } else {  // SELL
            totalQty -= tradedQty;
        }
    }

    public Long getId()                      { return id; }
    public int getTotalQty()                  { return totalQty; }
    public java.math.BigDecimal getAvgPrice() { return avgPrice; }
    public int getVersion()                   { return version; }
}
```

