```java
import org.springframework.retry.annotation.Backoff;
import org.springframework.retry.annotation.Retryable;
import jakarta.persistence.OptimisticLockException;
import org.springframework.orm.ObjectOptimisticLockingFailureException;

@Service
public class PositionService {
    private final PositionRepository repo;
    PositionService(PositionRepository r) { repo = r; }

    @Retryable(
        value = {OptimisticLockException.class,
                 ObjectOptimisticLockingFailureException.class},
        maxAttempts = 5,
        backoff = @Backoff(delay = 50, multiplier = 2.0)
    )
    @Transactional
    public PortfolioPosition applyTrade(String userId, String symbol,
                                         int qty, java.math.BigDecimal price,
                                         String type) {
        PortfolioPosition pos = repo
            .findByUserIdAndSymbol(userId, symbol)
            .orElseGet(() -> new PortfolioPosition(userId, symbol, 0, price));

        pos.applyTrade(qty, price, type);
        return repo.save(pos);
        // Hibernate: UPDATE portfolio_positions
        //            SET total_qty=?, avg_price=?, version=?
        //            WHERE id=? AND version=?  ← optimistic check
        // If version mismatch: 0 rows → OptimisticLockException → @Retryable kicks in
    }
}
```

